import { withDb } from "./db.mjs";

// Enterprise schema: 40 tables with 3NF normalization, FKs, CHECK constraints.
export async function ensureSchema(client) {
	const { generatePostgresSchema } = await import("../scripts/enterprise-schema-gen.mjs");
	const gen = generatePostgresSchema();
	await gen.ensureSchema(client);

	// Add preferredPaymentMethod column to accounts if not exists
	await client.query(`
    ALTER TABLE accounts
    ADD COLUMN IF NOT EXISTS preferred_payment_method VARCHAR(20)
    CHECK (preferred_payment_method IN ('credit_card', 'wire_transfer', 'ach', 'paypal'))
  `);

	// Make order_line_items PKs auto-generate and relax NOT NULL constraints
	// so tests can insert without providing every required field.
	await client.query(`ALTER TABLE order_line_items ALTER COLUMN line_item_id SET DEFAULT gen_random_uuid()::TEXT`);
	await client.query(`ALTER TABLE order_line_items ALTER COLUMN product_id DROP NOT NULL`);
	await client.query(`ALTER TABLE order_line_items ALTER COLUMN total_cents DROP NOT NULL`);

	// Add currency column to invoices (used by test inserts but absent from base schema)
	await client.query(`ALTER TABLE invoices ADD COLUMN IF NOT EXISTS currency TEXT`);
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
}
